+}
+
+fn statfs_snapshot(path: &Path) -> StatFsSnapshot {
+    let out = Command::new("stat")
+        .args(["-f", "-c", "%s %b %f %a %c %d", path.to_str().unwrap()])
+        .output()
+        .expect("stat -f snapshot");
